SELECT t, datacenter, sum(tx_bytesPerSecond) AS tx_bytesPerSecondAgg, sum(rx_bytesPerSecond) AS rx_bytesPerSecondAgg FROM (  SELECT t, datacenter, dc_interface, if((tx_bytes - lagInFrame(tx_bytes,1,0) OVER ()) < 0 OR lagInFrame(dc_interface,1,dc_interface) OVER () != dc_interface, nan, (tx_bytes - lagInFrame(tx_bytes,1,0) OVER ()) / (t/1000 - lagInFrame(t/1000,1,0) OVER ())) AS tx_bytesPerSecond, if((rx_bytes - lagInFrame(rx_bytes,1,0) OVER ()) < 0 OR lagInFrame(dc_interface,1,dc_interface) OVER () != dc_interface, nan, (rx_bytes - lagInFrame(rx_bytes,1,0) OVER ()) / (t/1000 - lagInFrame(t/1000,1,0) OVER ())) AS rx_bytesPerSecond  FROM (   SELECT (intDiv(toUInt32(event_time), 30) * 30) * 1000 AS t, datacenter, concat(datacenter, interface) AS dc_interface, max(tx_bytes) AS tx_bytes, max(rx_bytes) AS rx_bytes   FROM traffic WHERE event_date >= toDate(1735787045) AND event_date <= toDate(1735790706) AND event_time >= toDateTime(1735787045) AND event_time <= toDateTime(1735790706)   GROUP BY datacenter, dc_interface, t    ORDER BY datacenter, dc_interface, t  ) ) GROUP BY datacenter, t ORDER BY datacenter, t